<template>
  <view class="container">
    <!-- 未登录时显示登录按钮 -->
    <button v-if="!isLogin" 
      open-type="getUserInfo" 
      @getuserinfo="getUserInfo"
      class="login-btn">
      微信一键登录
    </button>

    <!-- 已登录展示用户信息 -->
    <view v-else class="user-info">
      <image :src="userInfo.avatarUrl" mode="widthFix"></image>
      <text>{{userInfo.nickname}}</text>
      <text>OpenID: {{userInfo.openid}}</text>
    </view>
  </view>
</template>

<script>
export default {
  data() {
    return {
      isLogin: false,
      userInfo: {
        nickname: '',
        avatarUrl: '',
        openid: ''
      }
    }
  },
  methods: {
    // 1. 获取微信用户信息（头像、昵称）
    async getUserInfo(e) {
      // 用户拒绝授权
      if (!e.detail.userInfo) {
        uni.showToast({ title: '登录失败', icon: 'none' });
        return;
      }
      
      // 保存头像昵称
      const { nickName, avatarUrl } = e.detail.userInfo;
      this.userInfo.nickname = nickName;
      this.userInfo.avatarUrl = avatarUrl;

      // 2. 获取code，用于换取openid
      this.getWxCode();
    },

    // 3. 获取微信code
    getWxCode() {
      uni.login({
        provider: 'weixin',
        success: async (res) => {
          if (res.code) {
            // 4. 把code传给后端，换取openid
            await this.loginToServer(res.code);
          }
        },
        fail: () => {
          uni.showToast({ title: '获取code失败', icon: 'none' });
        }
      });
    },

    // 5. 请求自己的后端接口
    async loginToServer(code) {
      uni.request({
        url: 'http://你的后端接口/wxLogin', // 替换成你的后端地址
        method: 'POST',
        data: {
          code: code,
          nickname: this.userInfo.nickname,
          avatar: this.userInfo.avatarUrl
        },
        success: (res) => {
          if (res.data.code === 200) {
            // 登录成功，保存openid
            this.userInfo.openid = res.data.openid;
            this.isLogin = true;
            uni.showToast({ title: '登录成功' });
          } else {
            uni.showToast({ title: '登录失败', icon: 'none' });
          }
        },
        fail: () => {
          uni.showToast({ title: '网络异常', icon: 'none' });
        }
      });
    }
  }
}
</script>

